VALUES
  ('optician-moex-02359', 'optician', 'optician-moex-107-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '散光受檢者在進行鐘面圖前，為了確保較清楚的鐘點線條為正確的散光軸，下列步驟何者最正確？', '["霧視到視標模糊，再退回到某方向是清晰的狀態", "達到最佳視力（best VA），鐘錶整體是最清晰的狀態", "過度負（overminus）到視標模糊，再退回到某方向是清晰的狀態", "縮短受檢者與視標之間的距離直到鐘錶整體是最清晰的狀態"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:37+00:00", "source_pdf_sha1": "bc120393b81a", "answer_pdf_sha1": "1e37b2c594ad", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02360', 'optician', 'optician-moex-107-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '下列那一種檢查宜減少背景照明以避免影響檢查結果？', '["最正球面度最佳視力（MPMVA）", "傑克森交叉圓柱鏡", "鐘面圖", "紅綠雙色檢查"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:37+00:00", "source_pdf_sha1": "bc120393b81a", "answer_pdf_sha1": "1e37b2c594ad", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02361', 'optician', 'optician-moex-107-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '有關雙眼平衡方式，下列敘述何者錯誤？', '["垂直稜鏡分離法（vertical prism dissociation）需要在兩眼前各放入相反但等量的稜鏡以幫助視標分離", "漢佛萊斯法（Humphriss method）提供雙眼融像（binocular lock of fusion）", "偏光濾片（polaroid）和隔板（septum）法都提供融像刺激（fusible stimuli）", "偏光濾片加紅綠視標平衡法需要霧視"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:37+00:00", "source_pdf_sha1": "bc120393b81a", "answer_pdf_sha1": "1e37b2c594ad", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02362', 'optician', 'optician-moex-107-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '下列檢查請按照驗光步驟排序：①散光軸確認  ②檢影鏡  ③初始球面度確認  ④散光度數確認  ⑤雙 眼平衡  ⑥第二次球面度確認', '["", "", "", "⑥"]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:37+00:00", "source_pdf_sha1": "bc120393b81a", "answer_pdf_sha1": "1e37b2c594ad", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 40, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02363', 'optician', 'optician-moex-107-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '有關融像性交叉柱鏡測試的描述，下列何者錯誤？', '["一般而言僅在近距離檢測", "檢查結果可用作老花的暫時加入度（tentative add）", "需明亮的照明環境（bright illumination）", "若受檢者未有老花眼症狀，以遠距離矯正處方開始檢查"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:37+00:00", "source_pdf_sha1": "bc120393b81a", "answer_pdf_sha1": "1e37b2c594ad", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 41, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02364', 'optician', 'optician-moex-107-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '測量遠用視力並矯正後，加入+1.50 D的暫定加入度並運用虛性相對調節力及實性相對調節力來微調暫定 加入度。若NRA為+0.75 D，PRA為-1.25 D，則此受檢者微調後的加入度（ADD）為多少？', '["+0.75 D", "+1.25 D", "+1.50 D", "+2.25 D"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:37+00:00", "source_pdf_sha1": "bc120393b81a", "answer_pdf_sha1": "1e37b2c594ad", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 42, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02365', 'optician', 'optician-moex-107-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '受檢者為49歲正視眼，經過測量後具有2.50 D的調節力，若戴上一副+1.50 D的單焦老花眼鏡，在不考 慮焦深（depth of focus）的狀態下，其清晰的調節範圍（range）為下列何者？', '["無限遠至40 cm", "67 cm至40 cm", "67 cm至25 cm", "40 cm至25 cm"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:37+00:00", "source_pdf_sha1": "bc120393b81a", "answer_pdf_sha1": "1e37b2c594ad", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 43, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02366', 'optician', 'optician-moex-107-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '受檢者有-1.25 DS近視，職業為近距離的雕刻工作。戴上原有的單焦老花眼鏡最近可以看到的距離為25 cm。 則此老花眼鏡度數為何？若想要配一副有矯正遠用視力（-1.25 DS）、並提供同樣可以看到25 cm近用距 離的雙焦眼鏡（bifocal），此雙焦眼鏡的近用加入度（ADD）又為何？', '["單焦老花眼鏡度數為+2.75 D，雙焦眼鏡近用加入度為+2.75 D", "單焦老花眼鏡度數為+2.75 D，雙焦眼鏡近用加入度為+4.00 D", "單焦老花眼鏡度數為+4.00 D，雙焦眼鏡近用加入度為+4.00 D", "單焦老花眼鏡度數為+4.00 D，雙焦眼鏡近用加入度為+5.25 D"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:37+00:00", "source_pdf_sha1": "bc120393b81a", "answer_pdf_sha1": "1e37b2c594ad", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 44, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02367', 'optician', 'optician-moex-107-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '有關老花近距離視力檢測的敘述，下列何者正確？', '["正視眼在老花眼初期，若從來沒戴過眼鏡，則不需要測量裸眼近用視力", "對於植入多焦點人工水晶體或需精準的評估遠用及近用視力者，應避免使用logMAR視標", "對於患有老年性黃斑部病變者，使用文字句子與單一字母的近用視標檢查結果會有相當差異", "若近用視力不佳時，應不要使用檯燈，避免造成眩光問題"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:37+00:00", "source_pdf_sha1": "bc120393b81a", "answer_pdf_sha1": "1e37b2c594ad", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 45, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02368', 'optician', 'optician-moex-107-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '以平行光進行諾特動態檢影（Nott dynamic retinoscopy）檢測，下列有關的步驟與過程何者錯誤？', '["視標應為文字、字母或圖片的近用視標", "應使用綜合驗光儀（phoropter），用來提高準確度", "檢測光束掃描時間越短越好，降低被檢者的調節作用", "若檢影的反射光為逆動時，檢影距離需要縮短"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:37+00:00", "source_pdf_sha1": "bc120393b81a", "answer_pdf_sha1": "1e37b2c594ad", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 46, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL)
